import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String userInput = request.getParameter("input");

        // Properly encoding user input before outputting it to the response
        response.getWriter().println("<html>");
        response.getWriter().println("<body>");
        response.getWriter().println("<h1>User Input: " + encodeHtml(userInput) + "</h1>");
        response.getWriter().println("</body>");
        response.getWriter().println("</html>");
    }

    // Method to properly encode user input to prevent XSS attacks
    private String encodeHtml(String input) {
        return input != null ? input.replace("&", "&amp;")
                                   .replace("<", "&lt;")
                                   .replace(">", "&gt;")
                                   .replace("\"", "&quot;")
                                   .replace("'", "&#39;") : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
